# 1. 替换分号为换行符，转换成标准 CSV 文本
csv_text = raw_data.replace(';', '\n')

# 2. 读入 pandas，并指定列名（防止空列捣乱，我们加几个占位名）
temp_columns = ['timestamp', 'date', 'open', 'close', 'volume', 'high', 'low',
                'dash1', 'change', 'change_pct', 'dash2', 'prev_close',
                'ma5', 'ma5_vol', 'ma10', 'ma10_vol', 'ma20', 'ma20_vol']

df = pd.read_csv(StringIO(csv_text), header=None, names=temp_columns)

# 3. 只保留您想要的字段
target_columns = ['date', 'open', 'close', 'volume', 'high', 'low',
                  'change', 'change_pct', 'prev_close', 'ma5', 'ma10', 'ma20']

clean_df = df[target_columns].copy()

# 4. 重命名列名（对接到您数据库或模型里的名字）
clean_df.columns = ['日期', '今开', '收盘', '成交量', '最高', '最低',
                    '涨跌额', '涨跌幅', '昨收', 'ma5', 'ma10', 'ma20']

# 5. 保存为干净的 CSV 文件
clean_df.to_csv('nasdaq_clean.csv', index=False, encoding='utf-8-sig')

